import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { slash } from '@vitest/utils/helpers'
import { dirname, relative, resolve } from 'pathe'
import { smoothDuration } from './duration-smoothing'

export type DurationHistory = Record<string, DurationObservation[]>

function observations(value: unknown): DurationObservation[] | null {
  if (typeof value === 'number' && Number.isFinite(value)) { return [{ duration: value, recordedAt: 0 }] }
  const entries = typeof value === 'object' && value !== null && 'observations' in value
    ? (value as { observations: unknown }).observations
    : [value]
  if (!Array.isArray(entries)) { return null }
  const parsed = entries.filter((entry): entry is DurationObservation => typeof entry === 'object' && entry !== null
    && typeof (entry as DurationObservation).duration === 'number' && Number.isFinite((entry as DurationObservation).duration)
    && typeof (entry as DurationObservation).recordedAt === 'number' && Number.isFinite((entry as DurationObservation).recordedAt))
  return parsed.length === entries.length ? parsed : null
}

export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
  try {
    const raw = JSON.parse(await readFile(resolve(root, path), 'utf8'))
    if (typeof raw !== 'object' || raw === null || Array.isArray(raw)) { return null }
    const cutoff = ttl > 0 ? Date.now() - ttl : -Infinity
    const history: DurationHistory = {}
    for (const [key, value] of Object.entries(raw)) {
      const entries = observations(value)
      if (!entries) { return null }
      history[key] = entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= cutoff)
    }
    return history
  }
  catch { return null }
}

export function durationFor(history: DurationHistory | null, file: string, root: string, ttl: number, smoothing: DurationSmoothing): number | undefined {
  const key = slash(relative(root, file))
  const cutoff = ttl > 0 ? Date.now() - ttl : -Infinity
  const entries = history?.[key]?.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= cutoff) ?? []
  return entries.length ? smoothDuration(entries, smoothing) : undefined
}

export async function writeDurationHistory(root: string, path: string, ttl: number, maxRuns: number, files: Array<{ filepath: string; duration: number }>): Promise<void> {
  const history = await readDurationHistory(root, path, ttl) ?? {}
  const now = Date.now()
  for (const file of files) {
    const key = slash(relative(root, file.filepath))
    history[key] = [...(history[key] ?? []), { duration: Math.round(file.duration), recordedAt: now }]
